```bash
(async () => {
  // ====== ここだけ置き換え ======
  const ID_TOKEN = "eyJhbGciOiJSUzI1NiIsInR5cCIgOiAiSldUIiwia2lkIiA6ICJxZDQtZmlzTlhzR29LSE10Ry10NFhMaHRDU25Db21TNTJ5OTRTdW4zUldrIn0..ZOTRvYwPMWrGkuGKMG8lfPEeFFrBNBOZhws-Iyo3oCRCvlTXNRepFejHmevWsqdulV7VVwEPR7gn68sNCU2QF0KhRiD5YPxUfJkPzSkotqPTpRQobgykboymRhyHv2lLaSKnppYpWlhHTHSpD0Qp7n5ULlgdpDfyqtrrwJ5T8IQvIAHqjha5se7IcjnHOwgJ3fEIfo9nomqycOCxujJZLurmFm67qE1aC3_13IxPeJdcqkqsMaexFatkFEDHLlQBJBzHFsMGR24h8DibbSbj7i1ubCymcngiT_x8jCcnGa15_mU_NExOIcvkAAw5zpN7s57zEWmBKN3Eqlg8elnGSQ";
  const DISCOVERY_URL = "https://rhbk-op-ninsho-dev.apps.ocp01.stg.jrqss.local/realms/test-realm/.well-known/openid-configuration";
  // ==============================

  // ---- base64url utilities ----
  const b64urlToBytes = (s) => {
    s = s.replace(/-/g, "+").replace(/_/g, "/");
    s += "=".repeat((4 - (s.length % 4)) % 4);
    const bin = atob(s);
    return Uint8Array.from(bin, (c) => c.charCodeAt(0));
  };
  const b64urlToJson = (s) => JSON.parse(new TextDecoder().decode(b64urlToBytes(s)));

  const splitJwt = (jwt) => {
    const parts = jwt.split(".");
    if (parts.length !== 3) throw new Error("Not a JWT (expected 3 parts)");
    return { h: parts[0], p: parts[1], s: parts[2], signingInput: `${parts[0]}.${parts[1]}` };
  };

  // ---- 1) decode header/payload ----
  const { h, p, s, signingInput } = splitJwt(ID_TOKEN);
  const header = b64urlToJson(h);
  const payload = b64urlToJson(p);

  console.log("=== header ===");
  console.log(header);
  console.log("=== payload ===");
  console.log(payload);

  // 必須観点（目視用）
  const must = ["iss", "aud", "exp", "iat", "sub"];
  console.log("=== required claims ===");
  for (const k of must) console.log(k, payload[k]);

  // ---- 2) time validation (exp/iat) ----
  const now = Math.floor(Date.now() / 1000);
  console.log("=== time check ===");
  console.log("now", now, new Date(now * 1000).toISOString());
  console.log("iat", payload.iat, payload.iat ? new Date(payload.iat * 1000).toISOString() : null);
  console.log("exp", payload.exp, payload.exp ? new Date(payload.exp * 1000).toISOString() : null);
  console.log("not expired =", typeof payload.exp === "number" ? (now < payload.exp) : "N/A");

  // ---- 3) fetch discovery -> jwks_uri ----
  const discRes = await fetch(DISCOVERY_URL);
  if (!discRes.ok) throw new Error(`Discovery fetch failed: HTTP ${discRes.status}`);
  const discovery = await discRes.json();
  const jwksUri = discovery.jwks_uri;
  console.log("jwks_uri =", jwksUri);

  // ---- 4) fetch JWKS & select key by kid ----
  const jwksRes = await fetch(jwksUri);
  if (!jwksRes.ok) throw new Error(`JWKS fetch failed: HTTP ${jwksRes.status}`);
  const jwks = await jwksRes.json();

  const kid = header.kid;
  const alg = header.alg;
  console.log("kid =", kid, "alg =", alg);

  const jwk = (jwks.keys || []).find((k) => k.kid === kid);
  if (!jwk) throw new Error(`No matching JWK for kid=${kid}`);

  console.log("matched jwk =", jwk);

  // ---- 5) signature verification (RS256 only) ----
  if (alg !== "RS256") {
    throw new Error(`This script supports RS256 only. token alg=${alg}`);
  }

  const cryptoKey = await crypto.subtle.importKey(
    "jwk",
    jwk,
    { name: "RSASSA-PKCS1-v1_5", hash: "SHA-256" },
    false,
    ["verify"]
  );

  const sigBytes = b64urlToBytes(s);
  const dataBytes = new TextEncoder().encode(signingInput);

  const verified = await crypto.subtle.verify(
    { name: "RSASSA-PKCS1-v1_5" },
    cryptoKey,
    sigBytes,
    dataBytes
  );

  console.log("=== signature verify ===");
  console.log("verified =", verified);

// ---- tamper test: payload を1文字改ざん（確実に verify 失敗） ----
const parts = ID_TOKEN.split(".");
const payloadPart = parts[1];

// payloadの先頭1文字を確実に変える（base64urlの文字を別の文字に）
const flip = (ch) => (ch === "a" ? "b" : "a");
const tamperedPayload = flip(payloadPart[0]) + payloadPart.slice(1);

const tamperedJwt = `${parts[0]}.${tamperedPayload}.${parts[2]}`;

const t = splitJwt(tamperedJwt);
const tamperedVerified = await crypto.subtle.verify(
  { name: "RSASSA-PKCS1-v1_5" },
  cryptoKey,
  b64urlToBytes(t.s),
  new TextEncoder().encode(t.signingInput)
);

console.log("tampered verified (should be false) =", tamperedVerified);


  // ---- summary ----
  console.log("=== RESULT SUMMARY ===");
  console.log({
    verified,
    notExpired: typeof payload.exp === "number" ? now < payload.exp : null,
    kid,
    alg,
    iss: payload.iss,
    aud: payload.aud,
    sub: payload.sub,
    nonce: payload.nonce ?? null
  });
})();
```
- 署名検証
verified = true → JWKでの署名検証成功（有効なID Tokenとして正しい）
- kid/alg 整合
alg = RS256
kid が JWKS に存在し matched jwk も取れている → 鍵選択もOK
- 改ざん検知
tampered verified = false → 改ざんしたJWTは検証失敗（期待どおり）
- 期限チェック
not expired = false は トークンが期限切れ

