1. `refresh_token` grant を実行して新しい `access_token` を取得する。
```bash
(async () => {
  const tokenUrl = `${__rt.KC_HOST}/realms/${__rt.REALM}/protocol/openid-connect/token`;

  const body = new URLSearchParams({
    grant_type: "refresh_token",
    client_id: __rt.CLIENT_ID,
    refresh_token: __rt.REFRESH_TOKEN
  });

  const res = await fetch(tokenUrl, {
    method: "POST",
    headers: {
      "Content-Type": "application/x-www-form-urlencoded",
      "Authorization": "Basic " + btoa(`${__rt.CLIENT_ID}:${__rt.CLIENT_SECRET}`)
    },
    body
  });

  const text = await res.text();
  console.log("HTTP", res.status);
  console.log(text);

  if (!res.ok) return;

  const json = JSON.parse(text);
  window.__rt.REFRESH_RESPONSE = json;
  window.__rt.ACCESS_TOKEN_NEW = json.access_token;
  window.__rt.REFRESH_TOKEN_NEW = json.refresh_token || null; // ローテ有無で変わる
  window.__rt.ID_TOKEN_NEW = json.id_token || null;

  console.log("saved: __rt.ACCESS_TOKEN_NEW / __rt.REFRESH_TOKEN_NEW / __rt.ID_TOKEN_NEW");
})();
```

