```bash
(async () => {
  const tokenUrl = `${__rt.KC_HOST}/realms/${__rt.REALM}/protocol/openid-connect/token`;

  const body = new URLSearchParams({
    grant_type: "refresh_token",
    client_id: __rt.CLIENT_ID,
    refresh_token: __rt.REFRESH_TOKEN // RT1
  });

  const res = await fetch(tokenUrl, {
    method: "POST",
    headers: {
      "Content-Type": "application/x-www-form-urlencoded",
      "Authorization": "Basic " + btoa(`${__rt.CLIENT_ID}:${__rt.CLIENT_SECRET}`)
    },
    body
  });

  const text = await res.text();
  console.log("=== refresh #1 (RT1 -> ?) ===");
  console.log("HTTP", res.status);
  console.log(text);

  if (!res.ok) return;

  const json = JSON.parse(text);
  window.__rt.RT1 = __rt.REFRESH_TOKEN;
  window.__rt.R1 = json; // 証跡用に保存
