```bash
(async () => {
  const JWKS_URL = "https://<KC_HOST>/realms/<REALM>/protocol/openid-connect/certs";
  const jwksRes = await fetch(JWKS_URL);
  const jwks = await jwksRes.json();

  const b64urlToBytes = (s) => {
    s = s.replace(/-/g, "+").replace(/_/g, "/");
    s += "=".repeat((4 - (s.length % 4)) % 4);
    const bin = atob(s);
    return Uint8Array.from(bin, (c) => c.charCodeAt(0));
  };
  const b64urlToJson = (s) => JSON.parse(new TextDecoder().decode(b64urlToBytes(s)));
  const splitJwt = (jwt) => {
    const parts = jwt.split(".");
    if (parts.length !== 3) throw new Error("Not a JWT (expected 3 parts)");
    return { h: parts[0], p: parts[1], s: parts[2], signingInput: `${parts[0]}.${parts[1]}` };
  };

  async function verifyJwt(jwt) {
    const { h, p, s, signingInput } = splitJwt(jwt);
    const header = b64urlToJson(h);
    const payload = b64urlToJson(p);

    const jwk = (jwks.keys || []).find(k => k.kid === header.kid);
    if (!jwk) return { ok: false, reason: `kid not found in JWKS: ${header.kid}`, header, payload };

    if (header.alg !== "RS256") return { ok: false, reason: `unsupported alg: ${header.alg}`, header, payload };

    const key = await crypto.subtle.importKey(
      "jwk",
      jwk,
      { name: "RSASSA-PKCS1-v1_5", hash: "SHA-256" },
      false,
      ["verify"]
    );

    const verified = await crypto.subtle.verify(
      { name: "RSASSA-PKCS1-v1_5" },
      key,
      b64urlToBytes(s),
      new TextEncoder().encode(signingInput)
    );

    const now = Math.floor(Date.now() / 1000);
    const notExpired = typeof payload.exp === "number" ? now < payload.exp : null;

    return { ok: verified, verified, notExpired, kid: header.kid, iss: payload.iss, aud: payload.aud, exp: payload.exp, iat: payload.iat };
  }

  const oldJwt = window.__old?.jwt || "<PASTE_OLD_TOKEN_HERE>";
  const newJwt = window.__new?.jwt || "<PASTE_NEW_TOKEN_HERE>";

  const r1 = await verifyJwt(oldJwt);
  const r2 = await verifyJwt(newJwt);

  console.log("=== verify old token with AFTER JWKS ===");
  console.log(r1);
  console.log("=== verify new token with AFTER JWKS ===");
  console.log(r2);

  console.log("=== SUMMARY ===");
  console.log({
    old: { kid: r1.kid, verified: r1.verified, notExpired: r1.notExpired, reason: r1.reason },
    new: { kid: r2.kid, verified: r2.verified, notExpired: r2.notExpired, reason: r2.reason }
  });
})();
```

